Here's how to test `DataFetcher` with proper timeout and cancellation handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        using var cts = new CancellationTokenSource();
        var fetcher = new DataFetcher(client);

        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler to avoid real HTTP calls
    private sealed class FakeHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode) { Content = new StringContent(_content) };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `_testContext.CancellationToken` | Enables cooperative cancellation with `[Timeout]` — without this, timeouts can't interrupt your async call |
| `Assert.ThrowsExactlyAsync<T>` | Modern replacement for `[ExpectedException]`, lets you inspect the exception |
| `sealed` test class | MSTest best practice for performance |
| Constructor-injected `TestContext` | Enables `readonly` and satisfies nullability |
| Fake `HttpMessageHandler` | Avoids real network calls; controls status codes and simulated delays |

The critical detail: **always flow `TestContext.CancellationToken`** through your async calls in tests with `[Timeout]`. Without it, the timeout attribute has no way to cancel the in-flight operation cooperatively.
